var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"이상하네……. 공장 안에 아무도 없어. ","JPN":"おかしいわ……工場の中に誰もいない。","ENG":"Odd... The factory seems empty.","TWN":"奇怪……工廠裡怎麼都沒人？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"전원도 내려가 있고……. 설마?","JPN":"電源も入っていないし……まさか？","ENG":"Even the power’s out... Could it be?!","TWN":"而且電源也都沒有開啟……難道？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CRIMINAL_NPC_ALPHA_QM","text":{"KOREA":"웰컴입니다. 이노베이션 대표.","JPN":"ウェルカムです。イノベーション代表。","ENG":"Welcome, CEO of Innovation.","TWN":"歡迎光臨，改革代表。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"……아니, 괴물 아가씨라고 불러드려야 할까요?","JPN":"……いや、化け物のお嬢様と呼ぶべきでしょうか？","ENG":"Or should I say, Ms. Monster?","TWN":"……不，還是我應該稱呼你為怪物小姐？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"일렉트로닉스 대표님! 무사하셨군요!","JPN":"エレクトロニクス代表！　ご無事だったのですね！","ENG":"Oh, thank goodness! You’re alive!","TWN":"電子代表！你沒事就好！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"정말 범인이 나타날지 반신반의했는데…….","JPN":"本当に犯人が現れるか半信半疑でしたが……","ENG":"I was half in disbelief whether you’d come or not...","TWN":"我原本還半信半疑地想說犯人真的會出現嗎……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"습격에 대비하라던 이 실장 말이 정확했어요.","JPN":"襲撃に備えろと言っていたシノザキ室長の言うとおりでした。","ENG":"Guess Chief Lee was right to prepare for an ambush.","TWN":"李室長說的果然沒錯，幸好我有準備！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네? 이진 언니가 대표님께 그런 말을 했다고요?","JPN":"はい？　ホノカさんが代表にそんなことを言ったのですか？","ENG":"Huh? Jin told you to do so?","TWN":"嗯？李珍姐已經有通知過代表嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇구나……. 저는 그런 줄도 모르고…….","JPN":"そうだったのね……私はそんなことも知らずに……","ENG":"I see... I didn’t know...","TWN":"原來如此……我都不知道……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"그래요. 알고 있었다면 여기 오지도 않았겠죠.","JPN":"そうです。知っていたらここには来もしなかったでしょう。","ENG":"Yes. If you knew, you wouldn’t have come.","TWN":"那當然，要是被你知道的話，你還會來嗎？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"네 범행은 여기서 끝이다, 이 괴물아.","JPN":"お前の犯行はここで終わりだ、この化け物め。","ENG":"Your terror ends here, you monster.","TWN":"你的罪行就到此為止，怪物！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"범행……?","JPN":"犯行……？","ENG":"Terror...?","TWN":"罪行……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아, 그렇구나! 제가 아직 설명을 안 드렸네요!","JPN":"あ、そうでしたね！　まだ説明しておりませんでした！","ENG":"Ah, I see! I haven’t explained it to you yet!","TWN":"喔～原來是這樣！都忘記跟你說明！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"흥, 나에게 총을 겨누다니 드디어 본색을 드러내는군.","JPN":"ふん、私に銃口を向けるとは、ついに本性を現したな。","ENG":"Hmph. Aiming a gun at me? So now you show your true ugly face.","TWN":"哼，竟然還拿槍指著我，露出你的真面目了吧！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"하지만 너무 무모하지 않나?","JPN":"だが無謀すぎるんじゃないか？","ENG":"But don’t you think it’s a little reckless?","TWN":"不過你的行為非常不明智！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"내 경호원들은 모두 카운터를 상대하기 위한 특수탄으로 무장했지.","JPN":"私のガードたちは全員、対カウンター用の特殊弾で武装している。","ENG":"My guards here are all equipped with special munition designed for Counters.","TWN":"我的保鑣們，可是都有裝上專門對付制裁者的特殊彈！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"홀로그램도 부릴 수 없는 지금은 역부족일 텐데?","JPN":"ホログラムも使えない今、お前の方が不利なはずだが？","ENG":"And as far as I know, you’re nothing without your holograms.","TWN":"而且你現在又叫不出全息圖，根本不是我的對手吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아뇨. 대표님은 지금 오해하고 계세요.","JPN":"いいえ。代表は誤解されています。","ENG":"There seems to be a misunderstanding.","TWN":"不是這樣的，代表似乎有所誤會。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"하긴, 설명보다 실제로 보는 게 이해하시기가 쉽겠네요.","JPN":"ですが、説明よりも実際に見た方が理解しやすいでしょう。","ENG":"But I suppose showing you proof would be faster than explaining...","TWN":"也是，與其用說的，不如直接讓你看清楚，"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>……범인의 실체를.</color>","JPN":"<color=#ffd34c>……犯人の実体を。</color>","ENG":"<color=#ffd34c>Who the real killer is.</color>","TWN":"<color=#ffd34c>……犯人的長相！</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ALPHA_08","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"뭐, 뭐야!? 생체 식별 신호는 패트릭으로 잡히는데……?!","JPN":"な、なんだ！？　生体識別信号はパトリックと出ているのに……！？","ENG":"W-what?! But the biometric signal displays it as Patrick!","TWN":"你…你是誰？！身分識別信號是派翠克……？！"},"stage":{"bg":"ALPHA_08","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"누구냐, <color=#ffd34c>넌</color>! 난 너 같은 여자애를 고용한 적 없어!","JPN":"誰だ、<color=#ffd34c>お前</color>は！\\n私はお前のような女を雇った覚えはないぞ！","ENG":"What are <color=#ffd34c>you</color>?! I don’t remember employing a girl like you!","TWN":"<color=#ffd34c>你</color>到底是誰！你不是我雇用的人！"},"stage":{"bg":"ALPHA_08","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"스틸레인제 제식 장비가 보편화되면서 생긴 맹점이에요.","JPN":"スチールレイン製の制式装備が普及したことによる盲点です。","ENG":"It’s an oversight of mass producing standardized Steel Lane gear.","TWN":"這是制式強化服普及化後出現的漏洞。"},"stage":{"bg":"ALPHA_08","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"평상시에도 헬멧을 착용하고 생체 식별 신호로 신원을 확인하게 되니까, 신호만 바꿀 수 있다면 다음은 쉽죠.","JPN":"普段からヘルメットを着用して、生体識別信号で身元を\\n確認するようになったので、信号さえ変えることができれば後は簡単です。","ENG":"They all wear helmets and we only verify personnel using the biometric signal, so if it is hacked and changed, no one will notice.","TWN":"平時也是戴著安全帽，透過身分識別信號來確認身分的，因此只要知道更改信號的方法，後面的事就簡單囉。"},"stage":{"bg":"ALPHA_08","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"지금까지 그런 식으로 침투한 거군요, <color=#ffd34c>실행범</color>.","JPN":"今までそのやり方で侵入したのでしょう、<color=#ffd34c>実行犯</color>は。","ENG":"So that’s how you’ve been able to get by unnoticed, <color=#ffd34c>killer</color>.","TWN":"這就是你的犯案手法吧，<color=#ffd34c>真兇</color>！"},"stage":{"bg":"ALPHA_08","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"신호를 바꾼다고? 하지만, 어떻게 그럴 수가……?","JPN":"信号を変える？　だが、どうやってそんなことが……！？","ENG":"Change the signal? But, how’s that even possible...?","TWN":"更改信號？怎麼可能……？"},"stage":{"bg":"ALPHA_08","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ALPHA_08","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_FAKE","text":{"KOREA":"……여기는 P-1. 1급 정보 유출. 작전 수행보다 퇴각을 우선시.","JPN":"……報告。P-1、1級情報流出。作戦遂行より退却を優先する。","ENG":"...This is P-1. Classified information leaked. Prioritize retreat over operation.","TWN":"……這裡P-1. 1級情報外洩，立刻終止行動，撤退。"},"stage":{"bg":"ALPHA_08","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"대표님!! 어서 제 뒤로 오세요!","JPN":"代表！！　私の後ろへ！","ENG":"Quick! Get behind me!","TWN":"代表！快躲到我後面來！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"괜찮으세요, 대표님?","JPN":"大丈夫ですか、代表？","ENG":"Are you all right?","TWN":"你沒事吧？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"네…… 네가 날 살린 건가? 윽……!","JPN":"お……お前が私を助けたのか？　うっ……！","ENG":"Y-you... saved me? Ngh...!","TWN":"是……你救了我的嗎？嗚……！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"총알이 어깨를 스쳐 지나갔어요. 다행히 큰 부상은 아니네요.","JPN":"弾丸が肩をかすめています。\\n幸い、大事に至るような怪我ではありません。","ENG":"The bullet grazed your shoulder. Luckily, it’s not fatal.","TWN":"子彈劃過你的肩膀，幸好沒有大礙。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"……고맙군. 내가 큰 착각을 하고 있었어.","JPN":"……ありがとう。私は大きな勘違いをしていたようだ。","ENG":"Thank you... It seems that I was wrong about you.","TWN":"……謝謝你，我誤會你了。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELECTRONICSCEO_NPC_ALPHA_NULL","text":{"KOREA":"그런데 제대로 보진 못했지만……. 그 여자애 생김새가…….","JPN":"ところで、しっかり確認できなかったが……あの女の顔は……","ENG":"I didn’t get a good look, but... that girl...","TWN":"不過，雖然我沒有看得很清楚……那個女的長得跟你……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"지, 지아야! 나다!","JPN":"ユ、ユイちゃん！　私よ！","ENG":"Jia! It’s me!","TWN":"小…小佳！是我！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네? 왜 그러세요, 세실리아 씨?","JPN":"え？　どうしたのですか、セシリアさん？","ENG":"Yes? What’s wrong, Cecilia?","TWN":"怎麼了，賽希莉亞？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"헤비암즈 군수 공장의 생산 이력을 조회해 봤는데…….","JPN":"ヘビーアームズ軍需工場の生産履歴を照会したんだけど……","ENG":"I took a look at the logs inside the Heavyarms’ munition factory...","TWN":"我查了重武裝工廠的生產履歷……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"네 말이 맞았다! <color=#ffd34c>밸런스 브레이커</color>를 생산한 이력이 남아 있어!","JPN":"君の言うとおりよ！　<color=#ffd34c>バランスブレイカー</color>の生産履歴があったわ！","ENG":"And you were right! There’s a record of <color=#ffd34c>Balance Breaker</color> being produced here!","TWN":"你說的沒錯！這裡有生產<color=#ffd34c>平衡破壞者</color>的紀錄！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네. 그렇다면 범인은 헤비암즈 대표…….","JPN":"はい。それでは犯人はヘビーアームズ代表……","ENG":"That must mean that the person behind all this is the CEO of Heavyarms...","TWN":"這麼說來，犯人就是重武裝代表……"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"재혁 오라버니셨군요.","JPN":"タツヤお兄様だったんですね。","ENG":"Shin Jaehyuk...","TWN":"也就是大哥！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그뿐만이 아니다!","JPN":"それだけじゃないわ！","ENG":"That’s not all!","TWN":"我還沒說完！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"잘 듣거라, 지아야.","JPN":"よく聞きなさい、ユイちゃん。","ENG":"Listen carefully, Jia.","TWN":"你聽好了，小佳。"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"여기서 제작된 <color=#ffd34c>밸런스 브레이커</color>는 한 정이 아니었느니라!!","JPN":"ここで作られた<color=#ffd34c>バランスブレイカー</color>は一丁だけじゃないわ！！","ENG":"It’s not just one <color=#ffd34c>Balance Breaker</color> that they made here!","TWN":"這裡製造出的<color=#ffd34c>平衡破壞者</color>，數量不只一個！！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"수십……. 아니, 어쩌면 백 정은 훌쩍 넘길 거다!","JPN":"数十……いや、もしかしたら百丁をはるかに超えてるかもしれない！","ENG":"I estimate it’s dozens... no, hundreds that were made here!","TWN":"可能超過幾十……不，或許超過幾百個！"},"stage":{"bg":"WORKSHOP","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};